question.answer:
void print_array(int* ptr, int len){
	while(len--){
		printf("%d%s", *(ptr++), len ? ", " : "\n");
	}
}

testcode.text:
regex_t regex;
int reti;
reti = regcomp(&regex, "(\\[|\\])", REG_EXTENDED | REG_NOSUB);
reti = regexec(&regex, input, 0, NULL, 0);
if (!reti) {
    printf("Square bracket detected! If you see this and didn't use any, show your code to Andrew.\n");
}
else if (reti == REG_NOMATCH) {
    printf("No square brackets detected!\n");
}
regfree(&regex);
